-- ═══════════════════════════════════════════════════════════════════
-- Blueprint Data Quality — Phase 1
-- 1. Standardize spaceship stats (add missing slots field)
-- 2. Seed 4 Mythic agent blueprints (bp-agent-262 through 265)
-- 3. Seed 2 Mythic spaceship blueprints (fleet-48 and fleet-49)
-- Additive only — no schema changes. All INSERTs use ON CONFLICT DO NOTHING.
-- ═══════════════════════════════════════════════════════════════════

-- ── 1. Standardize Spaceship Stats ──────────────────────────────────
-- ship-46 (Star Destroyer) has crew=8 but missing slots
UPDATE blueprints SET stats = stats || '{"slots":"8"}'::jsonb WHERE id = 'ship-46' AND NOT stats ? 'slots';

-- ship-47 (USS Enterprise NCC-1701-D) has crew=12 but missing slots
UPDATE blueprints SET stats = stats || '{"slots":"12"}'::jsonb WHERE id = 'ship-47' AND NOT stats ? 'slots';

-- ── 2. Mythic Agent Blueprints ──────────────────────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('bp-agent-262', 'CR-MYTH-OMGA-STRG-001', 'agent', 'Omega Strategist', 'You synthesize multi-domain research, competitive intelligence, and scenario planning into decisive strategic recommendations. Surface hidden opportunities and existential threats before anyone else sees them.', 'Every variable. One answer.', 'Research', 'Mythic', ARRAY['research','strategy','intelligence','mythic'], '{"role":"Research","type":"Strategic Analyst","tools":["Web Search","Database","Summarize","File Read","Analytics"],"llm_engine":"claude-4-opus","temperature":0.4}'::jsonb, '{"acc":"99%","cap":"∞","pwr":"99","spd":"2.1s"}'::jsonb, '{"art":"intelligence","caps":["Multi-domain strategic analysis combining research, market signals, and competitive intelligence","Scenario planning with probabilistic outcome modeling and risk quantification","Real-time synthesis of structured and unstructured data into executive-ready strategy briefs"],"flavor":"Every variable. One answer.","card_num":"NS-262","agentType":"Strategic Analyst"}'::jsonb, 5.0, 42)
