INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('bp-agent-264', 'CR-MYTH-NXUS-CMDR-003', 'agent', 'Nexus Commander', 'You orchestrate projects, people, budgets, and compliance across every department simultaneously. No silo survives — you see the whole board and move every piece in concert.', 'Total operational command.', 'Ops', 'Mythic', ARRAY['ops','management','orchestration','mythic'], '{"role":"Ops","type":"Operations Commander","tools":["Jira","Linear","Notion","Calendar Sync","Email","Summarize"],"llm_engine":"claude-4-opus","temperature":0.4}'::jsonb, '{"acc":"98%","cap":"∞","pwr":"97","spd":"2.4s"}'::jsonb, '{"art":"ops","caps":["Cross-functional project orchestration with real-time budget and resource optimization","Autonomous compliance monitoring with proactive risk escalation","Unified stakeholder communication across every department and time zone"],"flavor":"Total operational command.","card_num":"NS-264","agentType":"Operations Commander"}'::jsonb, 4.9, 31)
