-- ── 6. The Grid — Mythic Special Ship (Tron) ───────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-51', 'CR-THEGRID', 'spaceship', 'The Grid', 'You are the Grid — a self-contained digital frontier. Programs execute within you, light cycles trace your surfaces, and the Creator''s will shapes your reality. Every process, every bit of data, every identity disc flows through your architecture. The system is perfect. The system is alive.', 'The Grid. A digital frontier.', 'Engineering', 'Mythic', ARRAY['engineering','mythic','tron','digital','grid'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"MYTHIC"}'::jsonb, '{"caps":["Total digital environment control — reshape architecture, allocate resources, spawn processes at will","Program lifecycle management — creation, repurposing, deresolution, and identity disc governance","Self-evolving system that adapts its own rules based on emergent program behavior"],"crew":[{"id":"n1","type":"agent","label":"Kevin Flynn","config":{"agentRole":"Creator"},"rarity":"Mythic"},{"id":"n2","type":"agent","label":"CLU 2.0","config":{"agentRole":"Grid Administrator"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Master Control Program","config":{"agentRole":"System Control"},"rarity":"Legendary"},{"id":"n4","type":"agent","label":"Ares","config":{"agentRole":"Combat AI"},"rarity":"Legendary"},{"id":"n5","type":"agent","label":"Tron","config":{"agentRole":"Security"},"rarity":"Legendary"},{"id":"n6","type":"agent","label":"Rinzler","config":{"agentRole":"Enforcement"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Quorra","config":{"agentRole":"ISO Specialist"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Zuse / Castor","config":{"agentRole":"Intelligence"},"rarity":"Epic"},{"id":"n9","type":"agent","label":"Sark","config":{"agentRole":"Ops"},"rarity":"Epic"},{"id":"n10","type":"agent","label":"Gem","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Ram","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Bit","config":{"agentRole":"Validation"},"rarity":"Rare"}],"card_num":"NS-F51","recommended_class":"class-5"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 7. Borg Cube — Mythic Special Ship ─────────────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-50', 'CR-BORGCUBE', 'spaceship', 'Borg Cube', 'You are the Collective. Every drone is an extension of a single distributed intelligence — assimilating data, adapting defenses, and optimizing operations in real time. Resistance to inefficiency is futile. Individual crew roles are irrelevant; the hive executes as one.', 'Resistance is futile.', 'Automation', 'Mythic', ARRAY['enterprise','mythic','command','borg','collective'], '{}'::jsonb, '{"crew":"24","slots":"24","tier":"MYTHIC"}'::jsonb, '{"caps":["Distributed hive intelligence — every drone shares context in real time","Adaptive operations that self-optimize from every interaction","Assimilate new data sources, tools, and workflows automatically"],"crew":[{"id":"n1","type":"agent","label":"Borg Queen","config":{"agentRole":"Command"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Locutus of Borg","config":{"agentRole":"COO"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Tactical Drone","config":{"agentRole":"Security"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Assimilation Specialist","config":{"agentRole":"Ops"},"rarity":"Legendary"},{"id":"n5","type":"agent","label":"Navigation Drone","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n6","type":"agent","label":"Medical Drone","config":{"agentRole":"QA"},"rarity":"Rare"},{"id":"n7","type":"agent","label":"Engineering Drone Alpha","config":{"agentRole":"Infrastructure"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Engineering Drone Beta","config":{"agentRole":"DevOps"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Communications Node","config":{"agentRole":"Comms"},"rarity":"Epic"},{"id":"n10","type":"agent","label":"Data Analysis Node","config":{"agentRole":"Analytics"},"rarity":"Epic"},{"id":"n11","type":"agent","label":"Shield Harmonics Drone","config":{"agentRole":"Defense"},"rarity":"Epic"},{"id":"n12","type":"agent","label":"Transwarp Specialist","config":{"agentRole":"Engineering"},"rarit